# 输入获取
arr = list(map(int, input().split()))


def loop(arr, i, count):
    j = i + arr[i]

    if j == len(arr) - 1:
        return count
    elif j < len(arr) - 1:
        count += 1
        return loop(arr, j, count)
    else:
        return -1


# 算法入口
def getResult():
    res = []
    for i in range(1, len(arr)//2):
        res.append(loop(arr, i, 2))

    tmp = list(filter(lambda x: x>0, res))

    tmp.sort()

    if len(tmp) > 0:
        return tmp[0]
    else:
        return -1


# 算法调用
print(getResult())
